pattern_compile_expression(const widechar *input, const int input_max, int *input_crs, widechar *expr_data, const int expr_max, widechar *expr_crs, widechar *loop_cnts) {
	widechar *data;
	int expr_start, expr_end, expr_sub, expr_crs_prv;
	int input_end;
	int attrs0, attrs1;
	int set, esc, nest, i;

	switch (input[*input_crs]) {
	case '(':

		if (*expr_crs + 10 >= expr_max) return 0;

		(*input_crs)++;
		if (*input_crs >= input_max) return 0;

		/* find closing parenthesis */
		nest = esc = 0;
		for (input_end = *input_crs; input_end < input_max; input_end++) {
			if (input[input_end] == '\\' && !esc) {
				esc = 1;
				continue;
			}

			if (input[input_end] == '(' && !esc)
				nest++;
			else if (input[input_end] == ')' && !esc) {
				if (nest)
					nest--;
				else
					break;
			}

			esc = 0;
		}
		if (input_end >= input_max) return 0;

		EXPR_TYPE(*expr_crs) = PTN_GROUP;

		/* compile sub expressions */
		expr_crs_prv = *expr_crs;
		*expr_crs += 4;
		EXPR_DATA_0(expr_crs_prv) = *expr_crs;
		expr_sub = *expr_crs;
		EXPR_TYPE(expr_sub) = PTN_ERROR;
		EXPR_PRV(expr_sub) = PTN_END;
		EXPR_NXT(expr_sub) = PTN_END;
		if (!pattern_compile_1(input, input_end, input_crs, expr_data, expr_max, expr_crs, loop_cnts))
			return 0;
		(*input_crs)++;

		/* reset end expression */
		expr_end = *expr_crs;
		EXPR_NXT(expr_end) = expr_crs_prv;

		return *expr_crs += 3;

	case '!':
		if (*expr_crs + 10 >= expr_max) return 0;
		(*input_crs)++;
		EXPR_TYPE(*expr_crs) = PTN_NOT;
		expr_crs_prv = *expr_crs;
		*expr_crs += 4;
		EXPR_DATA_0(expr_crs_prv) = *expr_crs;

		/* create start expression */
		expr_start = *expr_crs;
		EXPR_TYPE(expr_start) = PTN_START;
		EXPR_PRV(expr_start) = PTN_END;
		*expr_crs += 3;
		EXPR_NXT(expr_start) = *expr_crs;

		/* compile sub expression */
		expr_sub = *expr_crs;
		EXPR_TYPE(expr_sub) = PTN_ERROR;
		EXPR_PRV(expr_sub) = expr_start;
		EXPR_NXT(expr_sub) = PTN_END;

		if (!pattern_compile_expression(input, input_max, input_crs, expr_data, expr_max, expr_crs, loop_cnts))
			return 0;

	case '+':
		if (*expr_crs + 4 >= expr_max) return 0;
		EXPR_TYPE(*expr_crs) = PTN_ONE_MORE;
		EXPR_DATA_1(*expr_crs) = (*loop_cnts)++;
		(*input_crs)++;
		return *expr_crs += 5;

	case '*':
		if (*expr_crs + 4 >= expr_max) return 0;
		EXPR_TYPE(*expr_crs) = PTN_ZERO_MORE;
		EXPR_DATA_1(*expr_crs) = (*loop_cnts)++;
		(*input_crs)++;
		return *expr_crs += 5;

	case '?':
		if (*expr_crs + 4 >= expr_max) return 0;
		EXPR_TYPE(*expr_crs) = PTN_OPTIONAL;
		(*input_crs)++;
		return *expr_crs += 4;

	case '|':
		if (*expr_crs + 5 >= expr_max) return 0;
		EXPR_TYPE(*expr_crs) = PTN_ALTERNATE;
		(*input_crs)++;
		return *expr_crs += 5;

	case '.':
		if (*expr_crs + 3 >= expr_max) return 0;
		EXPR_TYPE(*expr_crs) = PTN_ANY;
		(*input_crs)++;
		return *expr_crs += 3;

	case '%':
		if (*expr_crs + 5 >= expr_max) return 0;
		(*input_crs)++;
		if (*input_crs >= input_max) return 0;
		if (input[*input_crs] == '[') {
			set = 1;
			(*input_crs)++;
			for (input_end = *input_crs; input_end < input_max; input_end++)
				if (input[input_end] == ']') break;
			if (input_end >= input_max) return 0;
		} else {
			set = 0;
			input_end = *input_crs + 1;
		}
		EXPR_TYPE(*expr_crs) = PTN_ATTRIBUTES;
		attrs0 = attrs1 = 0;
		for (; (*input_crs) < input_end; (*input_crs)++) {
			switch (input[*input_crs]) {
			case '_': attrs0 |= CTC_Space; break;
			case '#': attrs0 |= CTC_Digit; break;
			case 'a': attrs0 |= CTC_Letter; break;
			case 'u': attrs0 |= CTC_UpperCase; break;
			case 'l': attrs0 |= CTC_LowerCase; break;
			case '.': attrs0 |= CTC_Punctuation; break;
			case '$': attrs0 |= CTC_Sign; break;
			case '~': attrs0 |= CTC_SeqDelimiter; break;
			case '<': attrs0 |= CTC_SeqBefore; break;
			case '>': attrs0 |= CTC_SeqAfter; break;
			case '0': attrs1 |= (CTC_UserDefined0 >> 16); break;
			case '1': attrs1 |= (CTC_UserDefined1 >> 16); break;
			case '2': attrs1 |= (CTC_UserDefined2 >> 16); break;
			case '3': attrs1 |= (CTC_UserDefined3 >> 16); break;
			case '4': attrs1 |= (CTC_UserDefined4 >> 16); break;
			case '5': attrs1 |= (CTC_UserDefined5 >> 16); break;
			case '6': attrs1 |= (CTC_UserDefined6 >> 16); break;
			case '7': attrs1 |= (CTC_UserDefined7 >> 16); break;
			case '^': attrs1 |= (CTC_EndOfInput >> 16); break;
			default: return 0;
			}
		}
		EXPR_DATA_0(*expr_crs) = attrs1;
		EXPR_DATA_1(*expr_crs) = attrs0;
		if (set) (*input_crs)++;
		return *expr_crs += 5;

	case '[':
		(*input_crs)++;
		if (*input_crs >= input_max) return 0;
		esc = 0;
		for (input_end = *input_crs; input_end < input_max; input_end++) {
			if (input[input_end] == '\\' && !esc) {
				esc = 1;
				continue;
			}
			if (input[input_end] == ']' && !esc) break;
			esc = 0;
		}
		if (input_end >= input_max) return 0;
		if (*expr_crs + 4 + (input_end - *input_crs) >= expr_max) return 0;
		EXPR_TYPE(*expr_crs) = PTN_CHARS;
		esc = 0;
		data = EXPR_DATA(*expr_crs);
		for (i = 1; *input_crs < input_end; (*input_crs)++) {
			if (input[*input_crs] == '\\' && !esc) {
				esc = 1;
				continue;
			}
			esc = 0;
			data[i++] = (widechar)input[*input_crs];
		}
		data[0] = i - 1;
		(*input_crs)++;
		return *expr_crs += 4 + data[0];

	case '^':
	case '$':
		if (*expr_crs + 3 >= expr_max) return 0;
		EXPR_TYPE(*expr_crs) = PTN_END_OF_INPUT;
		(*input_crs)++;
		return *expr_crs += 3;

	case '\\':
		(*input_crs)++;
		if (*input_crs >= input_max) return 0;

	default:
		if (*expr_crs + 5 >= expr_max) return 0;
		EXPR_TYPE(*expr_crs) = PTN_CHARS;
		EXPR_DATA_0(*expr_crs) = 1;
		EXPR_DATA_1(*expr_crs) = (widechar)input[*input_crs];
		(*input_crs)++;
		return *expr_crs += 5;
	}
}

_lou_getALine (FileInfo * nested)
{
/*Read a line of widechar's from an input file */
  int ch;
  int pch = 0;
  nested->linelen = 0;
  while ((ch = getAChar (nested)) != EOF)
    {
      if (ch == 13)
	continue;
      if (pch == '\\' && ch == 10)
	{
	  nested->linelen--;
	  continue;
	}
      if (ch == 10 || nested->linelen >= MAXSTRING-1)
	break;
      nested->line[nested->linelen++] = (widechar) ch;
      pch = ch;
    }
  nested->line[nested->linelen] = 0;
  nested->linepos = 0;
  if (ch == EOF)
    return 0;
  nested->lineNumber++;
  return 1;
}

_lou_showString (widechar const *chars, int length)
{
  /*Translate a string of characters to the encoding used in character 
  * operands */
  int charPos;
  int bufPos = 0;
  static char scratchBuf[MAXSTRING];
  scratchBuf[bufPos++] = '\'';
  for (charPos = 0; charPos < length; charPos++)
  {
      if (chars[charPos] >= 32 && chars[charPos] < 127)
	  scratchBuf[bufPos++] = (char) chars[charPos];
      else
	  {
	    char hexbuf[20];
	    int hexLength;
	    char escapeLetter;
	    int leadingZeros;
	    int hexPos;
	    hexLength = sprintf (hexbuf, "%x", chars[charPos]);
	    switch (hexLength)
	      {
	      case 1:
	      case 2:
	      case 3:
	      case 4:
	        escapeLetter = 'x';
	        leadingZeros = 4 - hexLength;
	        break;
	      case 5:
	        escapeLetter = 'y';
	        leadingZeros = 0;
	        break;
	      default:
	        escapeLetter = 'z';
	        leadingZeros = 0;
	        break;
	      }
	    if ((bufPos + leadingZeros + hexLength + 4) >= sizeof (scratchBuf))
	      break;
	    scratchBuf[bufPos++] = '\\';
	    scratchBuf[bufPos++] = escapeLetter;
	    for (hexPos = 0; hexPos < leadingZeros; hexPos++)
	      scratchBuf[bufPos++] = '0';
	    for (hexPos = 0; hexPos < hexLength; hexPos++)
	      scratchBuf[bufPos++] = hexbuf[hexPos];
	  }
    }
  scratchBuf[bufPos++] = '\'';
  scratchBuf[bufPos] = 0;
  return scratchBuf;
}

